import random
import math

def compute_model_placement(gpu_num, models):
    GPU_MEM = 80

    # Precompute KVPR ratio for each model
    for i, m in enumerate(models):
        m.kvpr_ratio = m.req_rate / m.slo
        m.id = i  # Unique identifier for tracking

    # Calculate KVPR for a GPU
    def gpu_kvpr(gpu_models):
        if not gpu_models:
            return 0.0
        total_kvpr = sum(m.kvpr_ratio for m in gpu_models)
        total_mem = sum(m.model_size for m in gpu_models)
        remaining = GPU_MEM - total_mem
        if remaining <= 0:
            return float('inf')
        if remaining == 0:
            return float('inf')
        return total_kvpr / remaining

    # Calculate max KVPR across all GPUs
    def max_kvpr(placement):
        max_val = 0.0
        for i in range(gpu_num):
            kvpr = gpu_kvpr(placement[i])
            if kvpr > max_val:
                max_val = kvpr
        return max_val

    # Initial solution: greedy by KVPR density
    def greedy_initial():
        placement = {i: [] for i in range(gpu_num)}
        gpu_mem = [0] * gpu_num

        # Sort by KVPR density (kvpr_ratio / model_size) descending
        sorted_models = sorted(models, key=lambda m: m.kvpr_ratio / max(m.model_size, 1), reverse=True)

        for model in sorted_models:
            best_gpu = -1
            best_kvpr = float('inf')

            # Try all GPUs that can fit the model
            for gpu in range(gpu_num):
                if gpu_mem[gpu] + model.model_size <= GPU_MEM:
                    temp = placement[gpu] + [model]
                    new_kvpr = gpu_kvpr(temp)
                    if new_kvpr < best_kvpr:
                        best_kvpr = new_kvpr
                        best_gpu = gpu

            if best_gpu != -1:
                placement[best_gpu].append(model)
                gpu_mem[best_gpu] += model.model_size
            else:
                # Fallback: put on GPU with most free memory
                best_gpu = max(range(gpu_num), key=lambda i: GPU_MEM - gpu_mem[i])
                placement[best_gpu].append(model)
                gpu_mem[best_gpu] += model.model_size

        return placement

    # Local search with best improvement
    def local_search(placement):
        best_placement = {i: list(placement[i]) for i in range(gpu_num)}
        best_score = max_kvpr(best_placement)

        improved = True
        while improved:
            improved = False
            best_move = None
            best_swap = None

            # Try single moves
            for gpu_from in range(gpu_num):
                for model in best_placement[gpu_from]:
                    for gpu_to in range(gpu_num):
                        if gpu_from == gpu_to:
                            continue

                        mem_to = sum(m.model_size for m in best_placement[gpu_to])
                        if mem_to + model.model_size > GPU_MEM:
                            continue

                        # Create new placement
                        new_placement = {i: list(best_placement[i]) for i in range(gpu_num)}
                        if model in new_placement[gpu_from]:
                            new_placement[gpu_from].remove(model)
                        new_placement[gpu_to].append(model)

                        new_score = max_kvpr(new_placement)
                        if new_score < best_score:
                            best_score = new_score
                            best_placement = new_placement
                            improved = True
                            break
                    if improved:
                        break
                if improved:
                    break

            if improved:
                continue

            # Try swaps
            for gpu1 in range(gpu_num):
                for gpu2 in range(gpu1 + 1, gpu_num):
                    if not best_placement[gpu1] or not best_placement[gpu2]:
                        continue

                    for model1 in best_placement[gpu1]:
                        for model2 in best_placement[gpu2]:
                            # Check memory constraints after swap
                            mem1 = sum(m.model_size for m in best_placement[gpu1]) - model1.model_size + model2.model_size
                            mem2 = sum(m.model_size for m in best_placement[gpu2]) - model2.model_size + model1.model_size

                            if mem1 > GPU_MEM or mem2 > GPU_MEM:
                                continue

                            new_placement = {i: list(best_placement[i]) for i in range(gpu_num)}
                            if model1 in new_placement[gpu1]:
                                new_placement[gpu1].remove(model1)
                            if model2 in new_placement[gpu2]:
                                new_placement[gpu2].remove(model2)
                            new_placement[gpu1].append(model2)
                            new_placement[gpu2].append(model1)

                            new_score = max_kvpr(new_placement)
                            if new_score < best_score:
                                best_score = new_score
                                best_placement = new_placement
                                improved = True
                                break
                        if improved:
                            break
                    if improved:
                        break
                if improved:
                    break

        return best_placement

    # Simulated annealing
    def simulated_annealing(initial_placement, iterations=1500):
        current = {i: list(initial_placement[i]) for i in range(gpu_num)}
        current_score = max_kvpr(current)
        best = {i: list(current[i]) for i in range(gpu_num)}
        best_score = current_score

        T_start = max(1.0, current_score * 0.3)
        T_end = 1e-5
        alpha = (T_end / T_start) ** (1.0 / iterations)

        T = T_start

        for _ in range(iterations):
            # Random move
            all_models = []
            for gpu_id in range(gpu_num):
                for model in current[gpu_id]:
                    all_models.append((model, gpu_id))

            if not all_models:
                break

            model_to_move, from_gpu = random.choice(all_models)
            to_gpu = random.randrange(gpu_num)

            if from_gpu == to_gpu:
                continue

            mem_to = sum(m.model_size for m in current[to_gpu])
            if mem_to + model_to_move.model_size > GPU_MEM:
                continue

            # Create neighbor
            neighbor = {i: list(current[i]) for i in range(gpu_num)}
            if model_to_move in neighbor[from_gpu]:
                neighbor[from_gpu].remove(model_to_move)
            neighbor[to_gpu].append(model_to_move)

            neighbor_score = max_kvpr(neighbor)

            # Metropolis criterion
            if neighbor_score < current_score or random.random() < math.exp((current_score - neighbor_score) / T):
                current = neighbor
                current_score = neighbor_score

                if current_score < best_score:
                    best = {i: list(current[i]) for i in range(gpu_num)}
                    best_score = current_score

            T *= alpha

        return best

    # Multi-start with different initializations
    best_placement = greedy_initial()
    best_score = max_kvpr(best_placement)

    # Try multiple random starts
    for _ in range(5):
        random.shuffle(models)
        current_placement = greedy_initial()

        # Local search
        current_placement = local_search(current_placement)
        current_score = max_kvpr(current_placement)

        # Simulated annealing
        current_placement = simulated_annealing(current_placement, iterations=1000)
        current_score = max_kvpr(current_placement)

        if current_score < best_score:
            best_score = current_score
            best_placement = current_placement

    # Final local search
    final_placement = local_search(best_placement)

    # Verify all models are placed
    placed_models = []
    for gpu_id in range(gpu_num):
        placed_models.extend(final_placement[gpu_id])

    if len(placed_models) != len(models):
        # If missing models, add them to GPUs with space
        missing_models = [m for m in models if m not in placed_models]
        for model in missing_models:
            for gpu_id in range(gpu_num):
                current_mem = sum(m.model_size for m in final_placement[gpu_id])
                if current_mem + model.model_size <= GPU_MEM:
                    final_placement[gpu_id].append(model)
                    break

    return final_placement

