import math

def compute_model_placement(gpu_num, models):
    GPU_MEM_SIZE = 80

    # Precompute kvpr contribution per model
    for m in models:
        m.kvpr_ratio = m.req_rate / m.slo

    def calculate_gpu_kvpr(gpu_models):
        if not gpu_models:
            return 0.0
        total_kvpr_ratio = sum(m.kvpr_ratio for m in gpu_models)
        total_model_size = sum(m.model_size for m in gpu_models)

        if total_model_size >= GPU_MEM_SIZE:
            return float('inf')

        return total_kvpr_ratio / (GPU_MEM_SIZE - total_model_size)

    def calculate_max_kvpr(placement):
        max_kvpr = 0.0
        for gpu_id in range(gpu_num):
            kvpr = calculate_gpu_kvpr(placement[gpu_id])
            max_kvpr = max(max_kvpr, kvpr)
        return max_kvpr

    # Initialize with empty placement
    best_placement = {gpu_id: [] for gpu_id in range(gpu_num)}
    best_kvpr = float('inf')

    # Try multiple random starts with local search
    for _ in range(100):
        # Random initial feasible placement
        placement = {gpu_id: [] for gpu_id in range(gpu_num)}
        gpu_mem_used = [0] * gpu_num

        shuffled_models = models.copy()
        random.shuffle(shuffled_models)

        for model in shuffled_models:
            feasible_gpus = []
            for gpu_id in range(gpu_num):
                if gpu_mem_used[gpu_id] + model.model_size <= GPU_MEM_SIZE:
                    feasible_gpus.append(gpu_id)

            if not feasible_gpus:
                # No feasible placement, try to make space
                best_gpu = min(range(gpu_num), key=lambda i: gpu_mem_used[i])
                placement[best_gpu].append(model)
                gpu_mem_used[best_gpu] += model.model_size
            else:
                # Place on GPU that minimizes KVPR increase
                best_gpu = min(feasible_gpus, 
                             key=lambda gpu_id: calculate_gpu_kvpr(placement[gpu_id] + [model]))
                placement[best_gpu].append(model)
                gpu_mem_used[best_gpu] += model.model_size

        # Local search: try moving models between GPUs
        improved = True
        while improved:
            improved = False
            current_kvpr = calculate_max_kvpr(placement)

            # Try all possible single model moves
            for src_gpu in range(gpu_num):
                for dst_gpu in range(gpu_num):
                    if src_gpu == dst_gpu:
                        continue

                    for i, model in enumerate(placement[src_gpu]):
                        # Check if move is feasible
                        src_mem = sum(m.model_size for m in placement[src_gpu]) - model.model_size
                        dst_mem = sum(m.model_size for m in placement[dst_gpu]) + model.model_size

                        if dst_mem > GPU_MEM_SIZE:
                            continue

                        # Perform move temporarily
                        placement[src_gpu].pop(i)
                        placement[dst_gpu].append(model)

                        new_kvpr = calculate_max_kvpr(placement)

                        if new_kvpr < current_kvpr:
                            improved = True
                            current_kvpr = new_kvpr
                            break
                        else:
                            # Revert move
                            placement[dst_gpu].remove(model)
                            placement[src_gpu].insert(i, model)

                    if improved:
                        break
                if improved:
                    break

        # Try swapping models between GPUs
        improved = True
        while improved:
            improved = False
            current_kvpr = calculate_max_kvpr(placement)

            for gpu1 in range(gpu_num):
                for gpu2 in range(gpu_num):
                    if gpu1 >= gpu2:
                        continue

                    for i, model1 in enumerate(placement[gpu1]):
                        for j, model2 in enumerate(placement[gpu2]):
                            # Check if swap is feasible
                            mem1 = sum(m.model_size for m in placement[gpu1]) - model1.model_size + model2.model_size
                            mem2 = sum(m.model_size for m in placement[gpu2]) - model2.model_size + model1.model_size

                            if mem1 > GPU_MEM_SIZE or mem2 > GPU_MEM_SIZE:
                                continue

                            # Perform swap temporarily
                            placement[gpu1][i], placement[gpu2][j] = model2, model1

                            new_kvpr = calculate_max_kvpr(placement)

                            if new_kvpr < current_kvpr:
                                improved = True
                                current_kvpr = new_kvpr
                                break
                            else:
                                # Revert swap
                                placement[gpu1][i], placement[gpu2][j] = model1, model2

                        if improved:
                            break
                    if improved:
                        break
                if improved:
                    break

        current_kvpr = calculate_max_kvpr(placement)
        if current_kvpr < best_kvpr:
            best_kvpr = current_kvpr
            best_placement = {gpu_id: placement[gpu_id].copy() for gpu_id in range(gpu_num)}

    return best_placement

