import numpy as np

def compute_model_placement(gpu_num, models):
    '''
    Args:
        gpu_num: Number of GPUs (int)
        models: List of models with .model_size, .req_rate, .slo

    Returns:
        dict: {gpu_id: [models assigned to that GPU]}
    '''
    GPU_MEM_SIZE = 80
    MAX_ITERATIONS = 1000
    PERTURBATION_STRENGTH = 3
    MAX_NO_IMPROVEMENT = 200

    # Assign a unique ID to each model for easier tracking.
    # Ensure this ID is consistent and unique across different calls if needed,
    # but for a single run, `id(m)` or an index is sufficient.
    for i, m in enumerate(models):
        m.kvpr_ratio = m.req_rate / m.slo
        m.model_id = i # Using index as ID

    # Helper function to calculate KVPR for a single GPU
    def calculate_gpu_kvpr(gpu_models):
        if not gpu_models:
            return 0.0
        total_kvpr_ratio = sum(m.kvpr_ratio for m in gpu_models)
        total_model_size = sum(m.model_size for m in gpu_models)

        if total_model_size > GPU_MEM_SIZE:
            return float('inf') # Constraint violation

        remaining_mem = GPU_MEM_SIZE - total_model_size
        if remaining_mem <= 0:
            return float('inf')

        return total_kvpr_ratio / remaining_mem

    # Helper function to calculate the maximum KVPR across all GPUs for a given placement
    def calculate_max_kvpr(placement):
        max_kvpr_val = 0.0
        for gpu_id in range(gpu_num):
            max_kvpr_val = max(max_kvpr_val, calculate_gpu_kvpr(placement[gpu_id]))
        return max_kvpr_val

    # Generates an initial feasible placement using a greedy approach.
    # Models are sorted by their 'score' (req_rate/slo) in descending order.
    # Each model is placed on the GPU that results in the minimum KVPR for that GPU,
    # provided the GPU has enough memory.
    def generate_initial_solution():
        placement = {gpu_id: [] for gpu_id in range(gpu_num)}
        gpu_current_mem = [0 for _ in range(gpu_num)]

        # Sorting by KVPR ratio (req_rate/slo) descending. This prioritizes
        # models that contribute more to the numerator of the KVPR.
        sorted_models = sorted(models, key=lambda m: m.kvpr_ratio, reverse=True)

        for model in sorted_models:
            best_gpu_id = -1
            min_potential_gpu_kvpr = float('inf')

            candidate_gpus = []
            for gpu_id in range(gpu_num):
                if gpu_current_mem[gpu_id] + model.model_size <= GPU_MEM_SIZE:
                    candidate_gpus.append(gpu_id)

            if not candidate_gpus:
                # This case indicates an issue with problem constraints or input.
                # If total model size exceeds total GPU capacity, it's unsolvable.
                # For robustness, assign to the first available GPU that *could* fit,
                # assuming total capacity is sufficient. If not, an error should be raised.
                found_fit = False
                for gpu_id in range(gpu_num):
                    if sum(m.model_size for m in placement[gpu_id]) + model.model_size <= GPU_MEM_SIZE:
                        best_gpu_id = gpu_id
                        found_fit = True
                        break
                if not found_fit:
                    raise ValueError(f"Cannot place model of size {model.model_size}. Problem might be infeasible.")
            else:
                for gpu_id in candidate_gpus:
                    # Calculate KVPR if the model were added to this GPU
                    temp_models_on_gpu = placement[gpu_id] + [model]
                    potential_kvpr = calculate_gpu_kvpr(temp_models_on_gpu)

                    if potential_kvpr < min_potential_gpu_kvpr:
                        min_potential_gpu_kvpr = potential_kvpr
                        best_gpu_id = gpu_id

                # If all potential KVPRs are inf (due to tiny remaining memory),
                # pick the first valid GPU that fits.
                if best_gpu_id == -1:
                    best_gpu_id = candidate_gpus[0]

            placement[best_gpu_id].append(model)
            gpu_current_mem[best_gpu_id] += model.model_size
        return placement

    # Local search to improve a given placement.
    # It explores moving a single model to a different GPU if it reduces the overall max KVPR.
    # This version uses a "first improvement" strategy.
    def local_search(placement):
        current_placement = {gpu_id: list(placement[gpu_id]) for gpu_id in range(gpu_num)}
        current_max_kvpr = calculate_max_kvpr(current_placement)

        while True:
            improved = False
            # Get all models and their current GPU IDs
            models_on_gpus = []
            for gpu_id in range(gpu_num):
                for model in current_placement[gpu_id]:
                    models_on_gpus.append((model, gpu_id))

            random.shuffle(models_on_gpus) # Shuffle to explore moves in a different order

            for model, from_gpu_id in models_on_gpus:
                for to_gpu_id in range(gpu_num):
                    if from_gpu_id == to_gpu_id:
                        continue

                    # Simulate the move
                    temp_placement = {gpu_id: list(current_placement[gpu_id]) for gpu_id in range(gpu_num)}

                    # Remove model from source GPU
                    temp_placement[from_gpu_id].remove(model)

                    # Check memory constraint for target GPU
                    target_gpu_current_size = sum(m.model_size for m in temp_placement[to_gpu_id])
                    if target_gpu_current_size + model.model_size <= GPU_MEM_SIZE:
                        temp_placement[to_gpu_id].append(model)

                        new_max_kvpr = calculate_max_kvpr(temp_placement)

                        # If improvement found, apply it and restart the search
                        if new_max_kvpr < current_max_kvpr:
                            current_placement = temp_placement
                            current_max_kvpr = new_max_kvpr
                            improved = True
                            break # Break inner loop (to_gpu_id)
                if improved:
                    break # Break outer loop (model, from_gpu_id)

            if not improved:
                break # No improvement in this full pass, local optimum reached
        return current_placement, current_max_kvpr

    # Perturbation function: randomly moves a specified number of models to different GPUs.
    def perturb(placement, num_moves):
        perturbed_placement = {gpu_id: list(placement[gpu_id]) for gpu_id in range(gpu_num)}

        # Collect all models and their current GPU indices
        models_info = []
        for gpu_id in range(gpu_num):
            for model in perturbed_placement[gpu_id]:
                models_info.append((model, gpu_id))

        if not models_info:
            return perturbed_placement # Nothing to perturb

        # Ensure we don't try to move more models than available
        actual_moves = min(num_moves, len(models_info))

        models_to_move_indices = random.sample(range(len(models_info)), actual_moves)

        for idx_to_move in models_to_move_indices:
            model_to_move, from_gpu_id = models_info[idx_to_move]

            # Find a random valid target GPU
            possible_target_gpus = [gpu_id for gpu_id in range(gpu_num) if gpu_id != from_gpu_id]
            random.shuffle(possible_target_gpus)

            moved = False
            for to_gpu_id in possible_target_gpus:
                target_gpu_current_size = sum(m.model_size for m in perturbed_placement[to_gpu_id])
                if target_gpu_current_size + model_to_move.model_size <= GPU_MEM_SIZE:
                    # Apply the move
                    perturbed_placement[from_gpu_id].remove(model_to_move)
                    perturbed_placement[to_gpu_id].append(model_to_move)
                    moved = True
                    break # Move to the next model to perturb
            # If a model couldn't be moved to any other GPU, it remains in its original GPU.
            # This is acceptable for perturbation.

        return perturbed_placement

    # --- Iterated Local Search (ILS) ---
    best_placement = generate_initial_solution()
    best_kvpr = calculate_max_kvpr(best_placement)

    no_improvement_counter = 0

    for iteration in range(MAX_ITERATIONS):
        # 1. Perturb the current best solution
        # We perturb the *best found so far*, not necessarily the one from the previous iteration's LS.
        # This is a standard ILS approach to explore from the current global optimum.
        current_solution_for_perturbation = {gpu_id: list(best_placement[gpu_id]) for gpu_id in range(gpu_num)}
        perturbed_solution = perturb(current_solution_for_perturbation, PERTURBATION_STRENGTH)

        # 2. Apply local search to the perturbed solution to find a new local optimum
        local_optimum_placement, local_optimum_kvpr = local_search(perturbed_solution)

        # 3. Acceptance Criterion: If the new local optimum is better than the overall best, update.
        if local_optimum_kvpr < best_kvpr:
            best_kvpr = local_optimum_kvpr
            best_placement = {gpu_id: list(local_optimum_placement[gpu_id]) for gpu_id in range(gpu_num)}
            no_improvement_counter = 0 # Reset counter on improvement
        else:
            no_improvement_counter += 1

        # Stop if no improvement for a long time
        if no_improvement_counter >= MAX_NO_IMPROVEMENT:
            break

    # Final validation: Ensure all models are placed and constraints are met.
    # Although the algorithms aim to do this, a final check is good practice.
    final_placed_models = []
    final_gpu_mem_usage = [0] * gpu_num
    for gpu_id in range(gpu_num):
        for model in best_placement[gpu_id]:
            final_placed_models.append(model)
            final_gpu_mem_usage[gpu_id] += model.model_size
            if final_gpu_mem_usage[gpu_id] > GPU_MEM_SIZE:
                # This should not happen if the algorithms are correct
                raise RuntimeError(f"Memory constraint violated on GPU {gpu_id}!")

    # Use set comparison for robust model checking
    input_model_ids = {m.model_id for m in models}
    placed_model_ids = {m.model_id for m in final_placed_models}

    if input_model_ids != placed_model_ids:
        missing_ids = input_model_ids - placed_model_ids
        extra_ids = placed_model_ids - input_model_ids

        error_message = "Model placement validation failed. "
        if missing_ids:
            error_message += f"Missing models with IDs: {missing_ids}. "
        if extra_ids:
            error_message += f"Foreign models with IDs: {extra_ids}. "

        # Attempt to correct missing models if possible, though this indicates a flaw.
        # A more robust solution would be to fix the algorithm that caused this.
        missing_models = [m for m in models if m.model_id in missing_ids]
        if missing_models:
            for model_to_add in missing_models:
                added = False
                for gpu_id in range(gpu_num):
                    if final_gpu_mem_usage[gpu_id] + model_to_add.model_size <= GPU_MEM_SIZE:
                        best_placement[gpu_id].append(model_to_add)
                        final_gpu_mem_usage[gpu_id] += model_to_add.model_size
                        added = True
                        break
                if not added:
                    raise RuntimeError(f"Could not place missing model {model_to_add.model_id} of size {model_to_add.model_size}.")
            # Re-check after adding
            final_placed_models = []
            for gpu_id in range(gpu_num):
                final_placed_models.extend(best_placement[gpu_id])
            placed_model_ids = {m.model_id for m in final_placed_models}
            if input_model_ids != placed_model_ids:
                 raise RuntimeError("Correction failed: Model placement mismatch persists.")

    # Ensure the output format is correct.
    return {gpu_id: list(gpu_models) for gpu_id, gpu_models in best_placement.items()}

import random
import math
import collections
import heapq

def compute_model_placement(gpu_num, models):
    '''
    Args:
        gpu_num: Number of GPUs (int)
        models: List of models with .model_size, .req_rate, .slo

    Returns:
        dict: {gpu_id: [models assigned to that GPU]}
    '''
    GPU_MEM_SIZE = 80
    MAX_ITERATIONS = 1000
    MAX_NO_IMPROVEMENT = 200

    # Add computed attributes to models for easier access
    for m in models:
        m.kvpr_ratio = m.req_rate / m.slo

    # Helper function to calculate KVPR for a single GPU
    def calculate_gpu_kvpr(gpu_models):
        if not gpu_models:
            return 0.0
        total_kvpr_ratio = sum(m.kvpr_ratio for m in gpu_models)
        total_model_size = sum(m.model_size for m in gpu_models)

        if total_model_size >= GPU_MEM_SIZE:
            return float('inf')

        remaining_mem = GPU_MEM_SIZE - total_model_size
        if remaining_mem <= 0:
            return float('inf')

        return total_kvpr_ratio / remaining_mem

    # Helper function to calculate the maximum KVPR across all GPUs for a given placement
    def calculate_max_kvpr(placement):
        max_kvpr_val = 0.0
        for gpu_id in range(gpu_num):
            gpu_kvpr = calculate_gpu_kvpr(placement[gpu_id])
            if gpu_kvpr == float('inf'):
                return float('inf')
            max_kvpr_val = max(max_kvpr_val, gpu_kvpr)
        return max_kvpr_val

    # Generate an initial feasible placement using a greedy approach
    def generate_initial_solution():
        placement = {gpu_id: [] for gpu_id in range(gpu_num)}
        gpu_current_mem = [0 for _ in range(gpu_num)]

        # Sort by KVPR ratio descending (prioritize models that contribute more to KVPR)
        sorted_models = sorted(models, key=lambda m: m.kvpr_ratio, reverse=True)

        for model in sorted_models:
            best_gpu_id = -1
            min_potential_gpu_kvpr = float('inf')

            # Find all GPUs that can accommodate the model
            candidate_gpus = []
            for gpu_id in range(gpu_num):
                if gpu_current_mem[gpu_id] + model.model_size <= GPU_MEM_SIZE:
                    candidate_gpus.append(gpu_id)

            if not candidate_gpus:
                # If no GPU can fit the model, it's a problem with model sizes or GPU count
                raise ValueError(f"Cannot fit model of size {model.model_size} on any GPU")

            # Find the best GPU to place the model
            for gpu_id in candidate_gpus:
                temp_models = placement[gpu_id] + [model]
                potential_kvpr = calculate_gpu_kvpr(temp_models)

                if potential_kvpr < min_potential_gpu_kvpr:
                    min_potential_gpu_kvpr = potential_kvpr
                    best_gpu_id = gpu_id

            if best_gpu_id != -1:
                placement[best_gpu_id].append(model)
                gpu_current_mem[best_gpu_id] += model.model_size
            else:
                # Should not happen due to earlier check
                raise RuntimeError("Failed to place model even when candidate GPUs exist")

        return placement

    # Local search: try to improve by moving one model at a time
    def local_search(placement):
        current_placement = {gpu_id: list(placement[gpu_id]) for gpu_id in range(gpu_num)}
        current_max_kvpr = calculate_max_kvpr(current_placement)

        improved = True
        while improved:
            improved = False
            # Collect all models with their GPUs
            models_on_gpus = []
            for gpu_id in range(gpu_num):
                for model in current_placement[gpu_id]:
                    models_on_gpus.append((model, gpu_id))

            # Shuffle to randomize search order
            random.shuffle(models_on_gpus)

            for model, from_gpu_id in models_on_gpus:
                # Try to move this model to another GPU
                for to_gpu_id in range(gpu_num):
                    if from_gpu_id == to_gpu_id:
                        continue

                    # Check if we can move the model
                    temp_placement = {gpu_id: list(current_placement[gpu_id]) for gpu_id in range(gpu_num)}
                    temp_placement[from_gpu_id].remove(model)

                    # Check target GPU
                    target_size = sum(m.model_size for m in temp_placement[to_gpu_id])
                    if target_size + model.model_size <= GPU_MEM_SIZE:
                        temp_placement[to_gpu_id].append(model)

                        new_max_kvpr = calculate_max_kvpr(temp_placement)

                        if new_max_kvpr < current_max_kvpr:
                            current_placement = temp_placement
                            current_max_kvpr = new_max_kvpr
                            improved = True
                            break  # Found an improvement, restart the search
            if improved:
                continue  # Continue searching for further improvements
        return current_placement, current_max_kvpr

    # Perturbation: randomly move some models to break local optima
    def perturb(placement, num_moves):
        perturbed_placement = {gpu_id: list(placement[gpu_id]) for gpu_id in range(gpu_num)}

        # Collect all models
        all_models = []
        for gpu_id in range(gpu_num):
            for model in perturbed_placement[gpu_id]:
                all_models.append((model, gpu_id))

        if not all_models:
            return perturbed_placement

        # Randomly select models to move
        to_move = random.sample(all_models, min(num_moves, len(all_models)))

        for model, from_gpu_id in to_move:
            # Remove from current GPU
            perturbed_placement[from_gpu_id].remove(model)

            # Try to place on another GPU
            possible_gpus = [gpu_id for gpu_id in range(gpu_num) 
                            if gpu_id != from_gpu_id and 
                            sum(m.model_size for m in perturbed_placement[gpu_id]) + model.model_size <= GPU_MEM_SIZE]

            if possible_gpus:
                to_gpu_id = random.choice(possible_gpus)
                perturbed_placement[to_gpu_id].append(model)

        return perturbed_placement

    # Initialize with a greedy solution
    best_placement = generate_initial_solution()
    best_kvpr = calculate_max_kvpr(best_placement)

    no_improvement_counter = 0

    # ILS loop
    for iteration in range(MAX_ITERATIONS):
        # Perturb the current best solution
        perturbed_placement = perturb(best_placement, 2)

        # Apply local search to the perturbed solution
        local_optimum_placement, local_optimum_kvpr = local_search(perturbed_placement)

        # Accept improvement
        if local_optimum_kvpr < best_kvpr:
            best_kvpr = local_optimum_kvpr
            best_placement = {gpu_id: list(local_optimum_placement[gpu_id]) for gpu_id in range(gpu_num)}
            no_improvement_counter = 0
        else:
            no_improvement_counter += 1

        if no_improvement_counter >= MAX_NO_IMPROVEMENT:
            break

    return {gpu_id: list(gpu_models) for gpu_id, gpu_models in best_placement.items()}

import random
import math
import itertools

def compute_model_placement(gpu_num, models):
    GPU_MEM_SIZE = 80

    # Precompute model attributes
    for m in models:
        m.kvpr_ratio = m.req_rate / m.slo
        m.density = m.kvpr_ratio / m.model_size if m.model_size > 0 else float('inf')

    # KVPR calculation for a group of models
    def calculate_gpu_kvpr(gpu_models):
        if not gpu_models:
            return 0.0
        total_kvpr = sum(m.kvpr_ratio for m in gpu_models)
        total_size = sum(m.model_size for m in gpu_models)
        if total_size >= GPU_MEM_SIZE:
            return float('inf')
        return total_kvpr / (GPU_MEM_SIZE - total_size)

    def calculate_max_kvpr(placement):
        return max(calculate_gpu_kvpr(placement[gpu_id]) for gpu_id in placement)

    # Generate initial solution using bin packing heuristics
    def generate_initial_solution():
        # Sort models by size descending (best-fit strategy)
        sorted_models = sorted(models, key=lambda m: (-m.model_size, -m.density))

        placement = {i: [] for i in range(gpu_num)}
        gpu_sizes = [0] * gpu_num
        gpu_kvprs = [0.0] * gpu_num

        for model in sorted_models:
            best_gpu = -1
            best_score = float('inf')

            # Evaluate all GPUs
            for gpu_id in range(gpu_num):
                if gpu_sizes[gpu_id] + model.model_size <= GPU_MEM_SIZE:
                    # Calculate potential KVPR after adding this model
                    temp_kvpr = (gpu_kvprs[gpu_id] + model.kvpr_ratio) / \
                               (GPU_MEM_SIZE - (gpu_sizes[gpu_id] + model.model_size))

                    # Consider balance across GPUs
                    # Favor GPUs with lower current KVPR and more remaining memory
                    score = temp_kvpr * (1 + 0.1 * gpu_sizes[gpu_id] / GPU_MEM_SIZE)

                    if score < best_score:
                        best_score = score
                        best_gpu = gpu_id

            if best_gpu == -1:
                # If no GPU can fit, force placement on least loaded GPU
                best_gpu = min(range(gpu_num), 
                             key=lambda i: gpu_sizes[i] if gpu_sizes[i] + model.model_size <= GPU_MEM_SIZE else float('inf'))

            placement[best_gpu].append(model)
            gpu_sizes[best_gpu] += model.model_size
            gpu_kvprs[best_gpu] += model.kvpr_ratio

        return placement

    # Tabu search with adaptive neighborhood
    def tabu_search(initial_solution):
        current_solution = {i: list(initial_solution[i]) for i in range(gpu_num)}
        current_kvpr = calculate_max_kvpr(current_solution)
        best_solution = {i: list(current_solution[i]) for i in range(gpu_num)}
        best_kvpr = current_kvpr

        # Tabu list: store recent moves (model_id, from_gpu, to_gpu)
        tabu_list = []
        max_tabu_size = min(20, len(models) // 2)

        # Adaptive perturbation parameters
        perturbation_size = max(1, len(models) // (3 * gpu_num))
        no_improve_counter = 0

        for iteration in range(200):
            best_move = None
            best_move_kvpr = float('inf')
            best_move_solution = None

            # Generate candidate moves
            candidates = []
            for from_gpu in range(gpu_num):
                if not current_solution[from_gpu]:
                    continue
                for model in current_solution[from_gpu]:
                    for to_gpu in range(gpu_num):
                        if from_gpu == to_gpu:
                            continue

                        # Check if move is tabu
                        move_hash = (id(model), from_gpu, to_gpu)
                        if move_hash in tabu_list:
                            continue

                        # Check memory constraint
                        to_gpu_size = sum(m.model_size for m in current_solution[to_gpu])
                        if to_gpu_size + model.model_size > GPU_MEM_SIZE:
                            continue

                        # Create new solution
                        new_solution = {i: list(current_solution[i]) for i in range(gpu_num)}
                        new_solution[from_gpu].remove(model)
                        new_solution[to_gpu].append(model)

                        new_kvpr = calculate_max_kvpr(new_solution)

                        # Aspiration criterion: accept if better than global best
                        if new_kvpr < best_kvpr or new_kvpr < current_kvpr:
                            candidates.append((move_hash, new_solution, new_kvpr))

            # Evaluate swap moves
            for gpu1 in range(gpu_num):
                for gpu2 in range(gpu1 + 1, gpu_num):
                    if not current_solution[gpu1] or not current_solution[gpu2]:
                        continue

                    for model1 in current_solution[gpu1]:
                        for model2 in current_solution[gpu2]:
                            # Check memory constraints
                            gpu1_size = sum(m.model_size for m in current_solution[gpu1])
                            gpu2_size = sum(m.model_size for m in current_solution[gpu2])

                            new_gpu1_size = gpu1_size - model1.model_size + model2.model_size
                            new_gpu2_size = gpu2_size - model2.model_size + model1.model_size

                            if new_gpu1_size > GPU_MEM_SIZE or new_gpu2_size > GPU_MEM_SIZE:
                                continue

                            move_hash = (id(model1), id(model2), gpu1, gpu2)
                            if move_hash in tabu_list:
                                continue

                            new_solution = {i: list(current_solution[i]) for i in range(gpu_num)}
                            new_solution[gpu1].remove(model1)
                            new_solution[gpu2].remove(model2)
                            new_solution[gpu1].append(model2)
                            new_solution[gpu2].append(model1)

                            new_kvpr = calculate_max_kvpr(new_solution)
                            if new_kvpr < best_kvpr or new_kvpr < current_kvpr:
                                candidates.append((move_hash, new_solution, new_kvpr))

            # Select best candidate
            if candidates:
                candidates.sort(key=lambda x: x[2])
                best_move, best_move_solution, best_move_kvpr = candidates[0]

                # Update tabu list
                tabu_list.append(best_move)
                if len(tabu_list) > max_tabu_size:
                    tabu_list.pop(0)

                current_solution = best_move_solution
                current_kvpr = best_move_kvpr

                if current_kvpr < best_kvpr:
                    best_solution = {i: list(current_solution[i]) for i in range(gpu_num)}
                    best_kvpr = current_kvpr
                    no_improve_counter = 0
                else:
                    no_improve_counter += 1
            else:
                no_improve_counter += 1

            # Adaptive perturbation
            if no_improve_counter >= 15:
                # Perturb the solution
                models_to_move = random.sample(models, min(perturbation_size, len(models)))

                # Remove selected models
                for model in models_to_move:
                    for gpu_id in range(gpu_num):
                        if model in current_solution[gpu_id]:
                            current_solution[gpu_id].remove(model)
                            break

                # Reinsert models using best-fit
                for model in models_to_move:
                    best_gpu = -1
                    best_kvpr_increase = float('inf')

                    for gpu_id in range(gpu_num):
                        current_size = sum(m.model_size for m in current_solution[gpu_id])
                        if current_size + model.model_size <= GPU_MEM_SIZE:
                            temp_kvpr = calculate_gpu_kvpr(current_solution[gpu_id] + [model])
                            kvpr_increase = temp_kvpr - calculate_gpu_kvpr(current_solution[gpu_id])

                            if kvpr_increase < best_kvpr_increase:
                                best_kvpr_increase = kvpr_increase
                                best_gpu = gpu_id

                    if best_gpu != -1:
                        current_solution[best_gpu].append(model)

                current_kvpr = calculate_max_kvpr(current_solution)
                no_improve_counter = 0

                # Reset tabu list after perturbation
                tabu_list = []

        return best_solution

    # Multi-start with different random seeds
    best_overall_solution = None
    best_overall_kvpr = float('inf')

    for seed in range(5):  # 5 different starting points
        random.seed(seed * 123)
        initial_solution = generate_initial_solution()
        solution = tabu_search(initial_solution)
        kvpr = calculate_max_kvpr(solution)

        if kvpr < best_overall_kvpr:
            best_overall_kvpr = kvpr
            best_overall_solution = solution

    # Final local optimization
    def final_optimize(solution):
        improved = True
        while improved:
            improved = False
            current_kvpr = calculate_max_kvpr(solution)

            # Try all single moves
            for from_gpu in range(gpu_num):
                for model in solution[from_gpu]:
                    for to_gpu in range(gpu_num):
                        if from_gpu == to_gpu:
                            continue

                        to_gpu_size = sum(m.model_size for m in solution[to_gpu])
                        if to_gpu_size + model.model_size > GPU_MEM_SIZE:
                            continue

                        # Make move
                        solution[from_gpu].remove(model)
                        solution[to_gpu].append(model)

                        new_kvpr = calculate_max_kvpr(solution)

                        if new_kvpr < current_kvpr:
                            improved = True
                            break
                        else:
                            # Revert move
                            solution[to_gpu].remove(model)
                            solution[from_gpu].append(model)

                    if improved:
                        break
                if improved:
                    break

        return solution

    if best_overall_solution:
        final_solution = final_optimize(best_overall_solution)
    else:
        final_solution = generate_initial_solution()

    return final_solution

import random
