def compute_model_placement(gpu_num, models):
    GPU_MEM_SIZE = 80

    # Precompute normalized values
    for m in models:
        m.kvpr_contrib = m.req_rate / m.slo
        m.density = m.kvpr_contrib / m.model_size

    def gpu_kvpr(gpu_models):
        if not gpu_models:
            return 0.0
        total_kvpr = sum(m.kvpr_contrib for m in gpu_models)
        total_size = sum(m.model_size for m in gpu_models)
        if total_size >= GPU_MEM_SIZE:
            return float('inf')
        return total_kvpr / (GPU_MEM_SIZE - total_size)

    def max_kvpr(placement):
        return max(gpu_kvpr(placement[gpu_id]) for gpu_id in range(gpu_num))

    # Initial greedy placement
    def greedy_placement():
        placement = {i: [] for i in range(gpu_num)}
        sizes = [0] * gpu_num

        # Sort by density (high density first)
        sorted_models = sorted(models, key=lambda m: m.density, reverse=True)

        for model in sorted_models:
            best_gpu = -1
            best_kvpr = float('inf')

            for gpu_id in range(gpu_num):
                if sizes[gpu_id] + model.model_size <= GPU_MEM_SIZE:
                    # Calculate what KVPR would be if we add this model
                    temp_models = placement[gpu_id] + [model]
                    kvpr = gpu_kvpr(temp_models)
                    if kvpr < best_kvpr:
                        best_kvpr = kvpr
                        best_gpu = gpu_id

            if best_gpu != -1:
                placement[best_gpu].append(model)
                sizes[best_gpu] += model.model_size
            else:
                # Should not happen if problem is feasible
                for gpu_id in range(gpu_num):
                    if sizes[gpu_id] + model.model_size <= GPU_MEM_SIZE:
                        placement[gpu_id].append(model)
                        sizes[gpu_id] += model.model_size
                        break

        return placement

    # Generate neighbor by moving one model from a high-KVPR GPU to a low-KVPR GPU
    def get_neighbor(placement):
        new_placement = {i: list(placement[i]) for i in range(gpu_num)}

        # Find GPUs with highest and lowest KVPR
        gpu_kvprs = [(gpu_id, gpu_kvpr(placement[gpu_id])) for gpu_id in range(gpu_num)]
        gpu_kvprs.sort(key=lambda x: x[1], reverse=True)

        source_gpu = gpu_kvprs[0][0]
        target_gpu = gpu_kvprs[-1][0]

        if not placement[source_gpu]:
            return placement

        # Try to move a model from source to target
        for model in list(placement[source_gpu]):
            target_size = sum(m.model_size for m in placement[target_gpu])
            if target_size + model.model_size <= GPU_MEM_SIZE:
                new_placement[source_gpu].remove(model)
                new_placement[target_gpu].append(model)
                return new_placement

        # If no direct move works, try swapping
        for model_src in placement[source_gpu]:
            for model_dst in placement[target_gpu]:
                src_size_without = sum(m.model_size for m in placement[source_gpu]) - model_src.model_size
                dst_size_without = sum(m.model_size for m in placement[target_gpu]) - model_dst.model_size

                if (src_size_without + model_dst.model_size <= GPU_MEM_SIZE and
                    dst_size_without + model_src.model_size <= GPU_MEM_SIZE):

                    new_placement[source_gpu].remove(model_src)
                    new_placement[target_gpu].remove(model_dst)
                    new_placement[source_gpu].append(model_dst)
                    new_placement[target_gpu].append(model_src)
                    return new_placement

        return placement

    # Simulated Annealing
    current = greedy_placement()
    best = {i: list(current[i]) for i in range(gpu_num)}
    current_kvpr = max_kvpr(current)
    best_kvpr = current_kvpr

    temperature = 100.0
    cooling_rate = 0.995
    iterations = 3000

    for _ in range(iterations):
        neighbor = get_neighbor(current)
        neighbor_kvpr = max_kvpr(neighbor)

        if neighbor_kvpr < best_kvpr:
            best = {i: list(neighbor[i]) for i in range(gpu_num)}
            best_kvpr = neighbor_kvpr

        if neighbor_kvpr < current_kvpr:
            current = neighbor
            current_kvpr = neighbor_kvpr
        else:
            delta = neighbor_kvpr - current_kvpr
            if random.random() < math.exp(-delta / temperature):
                current = neighbor
                current_kvpr = neighbor_kvpr

        temperature *= cooling_rate

    # Final local improvement
    improved = True
    while improved:
        improved = False
        for src_gpu in range(gpu_num):
            for dst_gpu in range(gpu_num):
                if src_gpu == dst_gpu:
                    continue

                for model in list(best[src_gpu]):
                    dst_size = sum(m.model_size for m in best[dst_gpu])
                    if dst_size + model.model_size <= GPU_MEM_SIZE:
                        # Try moving
                        temp_best = {i: list(best[i]) for i in range(gpu_num)}
                        temp_best[src_gpu].remove(model)
                        temp_best[dst_gpu].append(model)

                        if max_kvpr(temp_best) < best_kvpr:
                            best = temp_best
                            best_kvpr = max_kvpr(best)
                            improved = True
                            break
                if improved:
                    break
            if improved:
                break

    return best

