    def calculate_max_kvpr(placement):
        max_kvpr = 0.0
        for gpu_id in range(gpu_num):
            max_kvpr = max(max_kvpr, calculate_gpu_kvpr(placement[gpu_id]))
        return max_kvpr

    # Greedy assignment for initial placement
    def greedy_placement(models, gpu_num):
        placement = {gpu_id: [] for gpu_id in range(gpu_num)}
        gpu_mem_usage = [0] * gpu_num

        # Sort models by model_size descending (larger first)
        sorted_models = sorted(enumerate(models), key=lambda x: x[1].model_size, reverse=True)

        for idx, model in sorted_models:
            assigned = False
            # Try to place the model on the GPU with least current memory usage
            best_gpu = -1
            min_usage = float('inf')

            for gpu_id in range(gpu_num):
                if gpu_mem_usage[gpu_id] + model.model_size <= GPU_MEM_SIZE:
                    if gpu_mem_usage[gpu_id] < min_usage:
                        min_usage = gpu_mem_usage[gpu_id]
                        best_gpu = gpu_id

            if best_gpu != -1:
                placement[best_gpu].append(model)
                gpu_mem_usage[best_gpu] += model.model_size
                assigned = True

            # If we still couldn't place it, find any available GPU
            if not assigned:
                for gpu_id in range(gpu_num):
                    if gpu_mem_usage[gpu_id] + model.model_size <= GPU_MEM_SIZE:
                        placement[gpu_id].append(model)
                        gpu_mem_usage[gpu_id] += model.model_size
                        assigned = True
                        break

            if not assigned:
                # If still can't place, it's a problem with the model or the system
                # This should not normally happen if GPU memory allows
                raise ValueError(f"Cannot place model {idx} (size: {model.model_size})")

        return placement

    # Local search improvement
    def local_search(placement):
        improved = True
        while improved:
            improved = False
            max_kvpr = calculate_max_kvpr(placement)

            # Try moving each model to different GPUs
            for gpu_id in range(gpu_num):
                gpu_models = placement[gpu_id][:]
                for i in range(len(gpu_models)):
                    model = gpu_models[i]

                    # Temporarily remove the model
                    new_placement = {k: v[:] for k, v in placement.items()}
                    new_placement[gpu_id].remove(model)

                    # Try to place it on other GPUs
                    for new_gpu_id in range(gpu_num):
                        if gpu_id == new_gpu_id:
                            continue
                        if sum(m.model_size for m in new_placement[new_gpu_id]) + model.model_size <= GPU_MEM_SIZE:
                            new_placement[new_gpu_id].append(model)

                            # Check if this improves the maximum KVPR
                            new_max_kvpr = calculate_max_kvpr(new_placement)
                            if new_max_kvpr < max_kvpr:
                                placement = new_placement
                                max_kvpr = new_max_kvpr
                                improved = True
